Library.Command:
SET ANSI_NULLS ON GO SET QUOTED_IDENTIFIER ON GO
-- ============================================= -- Author: Daniel Šašek -- Create date: 2023-12-01 -- Description: Interface pro načítání naplánovaných aktivit -- ============================================= #MODIFIER# FUNCTION #NAME# ( @AccountID INT, @FolderGroupSegmentIdent VARCHAR(100), @SegmentTypeID VARCHAR(100), @FolderTreeIdent VARCHAR(900) ) RETURNS TABLE AS RETURN (
WITH PermissionSources AS ( SELECT PermissionSourceFolderTreeID = fot.ID ,PermissionID = aftp.PermissionID FROM dbo.AccountFolderTree AS aft INNER JOIN dbo.Account AS acc ON acc.ID = aft.AccountID AND acc.[State] = 1 INNER JOIN dbo.AccountFolderTreePermission AS aftp ON aftp.AccountFolderTreeID = aft.ID INNER JOIN dbo.FolderTree AS fot ON fot.ID = aft.FolderTreeID AND fot.InheritFromParent = 0 INNER JOIN dbo.Folder AS fol ON fol.[State] != 2 AND fol.ID = fot.FolderID AND fol.FolderGroupSegmentIdent = @FolderGroupSegmentIdent WHERE aft.AccountID = @AccountID
UNION ALL
SELECT PermissionSourceFolderTreeID = fot.ID ,PermissionID = gftp.PermissionID FROM dbo.GroupAccount AS gra INNER JOIN dbo.[Group] AS gro ON gro.ID = gra.GroupID AND gro.[State] = 1 INNER JOIN dbo.GroupFolderTree AS gft ON gft.GroupId = gra.GroupId INNER JOIN dbo.GroupFolderTreePermission AS gftp ON gftp.GroupFolderTreeID = gft.ID INNER JOIN dbo.FolderTree AS fot ON fot.ID = gft.FolderTreeID AND fot.InheritFromParent = 0 INNER JOIN dbo.Folder AS fol ON fol.[State] != 2 AND fol.ID = fot.FolderID AND fol.FolderGroupSegmentIdent = @FolderGroupSegmentIdent WHERE gra.AccountID = @AccountID
) ,UserSegmentAccess AS ( SELECT sgt.ID FROM dbo.SegmentType AS sgt INNER JOIN dbo.[Role] AS rol ON rol.ASPNETRoleID = sgt.ASPNETRoleID INNER JOIN dbo.AccountPermissionStaticComputed AS apsc ON apsc.PermissionID = rol.PermissionID WHERE apsc.AccountID = @AccountID ) SELECT DISTINCT pes.PermissionID FROM PermissionSources AS pes INNER JOIN dbo.FolderTree AS fot ON COALESCE(fot.InheritFromFolderTreeID, fot.ID) = pes.PermissionSourceFolderTreeID AND fot.Ident = @FolderTreeIdent INNER JOIN usr.ITSMFolderTreeSegmentType AS itsFotSgt ON itsFotSgt.FolderTreeID = fot.ID AND itsFotSgt.SegmentTypeID = @SegmentTypeID AND itsFotSgt.SegmentTypeID IN (SELECT ID FROM UserSegmentAccess)
);
